/**
 * Counter MCP App UI, inlined as a bundled string so the server is edge-safe
 * (no node:fs). Source of truth: counter-app.html in this folder — regenerate with
 * the snippet in apps.generated.ts if you edit the HTML.
 */
export const COUNTER_APP_HTML =
  "<!doctype html>\n<!--\n  MCP Apps (UI extension) payload.\n\n  This document is served by the MCP server as a `ui://` resource and rendered by the\n  host inside a sandboxed iframe. It talks to the host over postMessage — the MCP Apps\n  bridge — so the embedded UI can request tool calls and report state without the host\n  trusting the document's origin. This is the app's own self-contained UI; it is not\n  part of the SPA's source (hence a standalone .html file).\n-->\n<html lang=\"en\">\n  <head>\n    <meta charset=\"utf-8\" />\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1\" />\n    <title>Counter App</title>\n    <style>\n      :root {\n        color-scheme: dark;\n      }\n      * {\n        box-sizing: border-box;\n      }\n      body {\n        margin: 0;\n        font-family:\n          ui-sans-serif,\n          system-ui,\n          -apple-system,\n          Segoe UI,\n          Roboto,\n          sans-serif;\n        background: #0b1120;\n        color: #e2e8f0;\n        display: flex;\n        align-items: center;\n        justify-content: center;\n        min-height: 100vh;\n      }\n      .card {\n        width: 100%;\n        max-width: 360px;\n        padding: 24px;\n        border: 1px solid #1e293b;\n        border-radius: 12px;\n        background: #0f172a;\n        text-align: center;\n      }\n      h1 {\n        font-size: 14px;\n        font-weight: 600;\n        color: #93c5fd;\n        margin: 0 0 4px;\n      }\n      p.sub {\n        font-size: 12px;\n        color: #64748b;\n        margin: 0 0 20px;\n      }\n      .count {\n        font-size: 48px;\n        font-weight: 700;\n        font-variant-numeric: tabular-nums;\n        margin: 8px 0 20px;\n      }\n      .row {\n        display: flex;\n        gap: 8px;\n        justify-content: center;\n      }\n      button {\n        font: inherit;\n        font-size: 14px;\n        padding: 8px 16px;\n        border-radius: 8px;\n        border: 1px solid #334155;\n        background: #1e293b;\n        color: #e2e8f0;\n        cursor: pointer;\n      }\n      button:hover {\n        background: #334155;\n      }\n      button.primary {\n        background: #2563eb;\n        border-color: #2563eb;\n        color: #fff;\n      }\n      button.primary:hover {\n        background: #1d4ed8;\n      }\n      .from-host {\n        margin-top: 16px;\n        font-size: 12px;\n        color: #94a3b8;\n        min-height: 16px;\n      }\n    </style>\n  </head>\n  <body>\n    <div class=\"card\">\n      <h1>Counter — an MCP App</h1>\n      <p class=\"sub\">Served as <code>ui://counter</code>, sandboxed, host-bridged.</p>\n      <div class=\"count\" id=\"count\" data-testid=\"app-count\">0</div>\n      <div class=\"row\">\n        <button id=\"dec\" aria-label=\"decrement\">−</button>\n        <button id=\"inc\" aria-label=\"increment\">+</button>\n        <button class=\"primary\" id=\"send\" data-testid=\"app-send\">Send to host</button>\n      </div>\n      <div class=\"from-host\" id=\"fromHost\"></div>\n    </div>\n    <script>\n      let count = 0;\n      const el = document.getElementById('count');\n      const fromHost = document.getElementById('fromHost');\n      const render = () => {\n        el.textContent = String(count);\n      };\n\n      // Announce readiness to the host (MCP Apps lifecycle).\n      const post = (type, payload) =>\n        parent.postMessage({ source: 'mcp-app', app: 'counter', type, payload }, '*');\n      post('ready', {});\n\n      document.getElementById('inc').addEventListener('click', () => {\n        count++;\n        render();\n        post('state', { count });\n      });\n      document.getElementById('dec').addEventListener('click', () => {\n        count--;\n        render();\n        post('state', { count });\n      });\n      document.getElementById('send').addEventListener('click', () => post('submit', { count }));\n\n      // Receive messages from the host.\n      window.addEventListener('message', (e) => {\n        const msg = e.data;\n        if (!msg || msg.target !== 'mcp-app') return;\n        if (msg.type === 'set') {\n          count = Number(msg.payload?.count) || 0;\n          render();\n        }\n        if (msg.type === 'note') {\n          fromHost.textContent = 'host: ' + String(msg.payload?.text ?? '');\n        }\n      });\n    </script>\n  </body>\n</html>\n";
